CREATE TABLE IF NOT EXISTS temp_json_ids (materiaalnaam text, id text);
TRUNCATE TABLE temp_json_ids;

UPDATE main_material_list 
SET id = temp_json_ids.id
FROM temp_json_ids
WHERE main_material_list.materiaalnaam = temp_json_ids.materiaalnaam
AND main_material_list.id IS NULL;


UPDATE main_material_list
SET id = temp_json_ids.id
FROM temp_json_ids
WHERE TRIM(main_material_list.materiaalnaam) = TRIM(temp_json_ids.materiaalnaam)
AND main_material_list.id IS NULL;

DROP TABLE temp_json_ids;